// src/App.js
import React, { useState, useEffect } from "react";
import Dice from "react-dice-roll";

// --- Board Image path ---
const boardImage = "/torahpoly_board.png";

// --- Red Properties ---
const schemRoyalEstates = {
  type: "property",
  name: "Schem Royal Estates",
  colorGroup: "red",
  price: 300,
  rent: { base: 60, house1: 150, house2: 350, house3: 700, hotel: 800 },
  buildCost: { house: 200, hotel: 300 },
  houses: 0,
  hotel: false,
  ownerIndex: null,
};

const schemYosephGardens = {
  type: "property",
  name: "Schem Yoseph Gardens",
  colorGroup: "red",
  price: 300,
  rent: { base: 60, house1: 150, house2: 350, house3: 700, hotel: 800 },
  buildCost: { house: 200, hotel: 300 },
  houses: 0,
  hotel: false,
  ownerIndex: null,
};

const schemDreamResorts = {
  type: "property",
  name: "Schem Dream Resorts",
  colorGroup: "red",
  price: 300,
  rent: { base: 50, house1: 100, house2: 650, house3: 750, hotel: 750 },
  buildCost: { house: 150, hotel: 250 },
  houses: 0,
  hotel: false,
  ownerIndex: null,
};

// --- Yellow Property ---
const ephraimHilltops = {
  type: "property",
  name: "Ephraim Hilltops",
  colorGroup: "yellow",
  price: 300,
  rent: { base: 50, house1: 300, house2: 400, house3: 500, hotel: 800 },
  buildCost: { house: 50, hotel: 100 },
  houses: 0,
  hotel: false,
  ownerIndex: null,
};

// --- Green Properties ---
const gushKatif = {
  type: "property",
  name: "Gush Katif",
  colorGroup: "green",
  price: 350,
  rent: { base: 60, house1: 150, house2: 350, house3: 700, hotel: 1000 },
  buildCost: { house: 150, hotel: 250 },
  houses: 0,
  hotel: false,
  ownerIndex: null,
};

const neveDekalim = {
  type: "property",
  name: "Neve Dekalim",
  colorGroup: "green",
  price: 350,
  rent: { base: 50, house1: 200, house2: 300, house3: 650, hotel: 800 },
  buildCost: { house: 150, hotel: 200 },
  houses: 0,
  hotel: false,
  ownerIndex: null,
};

const ganOr = {
  type: "property",
  name: "Gan Or",
  colorGroup: "green",
  price: 350,
  rent: { base: 50, house1: 100, house2: 300, house3: 650, hotel: 800 },
  buildCost: { house: 150, hotel: 200 },
  houses: 0,
  hotel: false,
  ownerIndex: null,
};

// --- Purple Properties ---
const jerusalemHills = {
  type: "property",
  name: "Jerusalem Hills",
  colorGroup: "purple",
  price: 150,
  rent: { base: 10, house1: 200, house2: 250, house3: 300, hotel: 400 },
  buildCost: { house: 50, hotel: 100 },
  houses: 0,
  hotel: false,
  ownerIndex: null,
};

const jerusalemHillsOrchard = {
  type: "property",
  name: "Jerusalem Hills Orchard",
  colorGroup: "purple",
  price: 150,
  rent: { base: 10, house1: 200, house2: 250, house3: 300, hotel: 400 },
  buildCost: { house: 50, hotel: 100 },
  houses: 0,
  hotel: false,
  ownerIndex: null,
};

// --- Gold Properties ---
const hevronElonMamrei = {
  type: "property",
  name: "Hevron Elon Mamrei",
  colorGroup: "gold",
  price: 240,
  rent: { base: 30, house1: 70, house2: 200, house3: 550, hotel: 650 },
  buildCost: { house: 80, hotel: 150 },
  houses: 0,
  hotel: false,
  ownerIndex: null,
};

const hevronLuxuryCondos = {
  type: "property",
  name: "Hevron Luxury Condos",
  colorGroup: "gold",
  price: 240,
  rent: { base: 25, house1: 60, house2: 175, house3: 500, hotel: 600 },
  buildCost: { house: 60, hotel: 100 },
  houses: 0,
  hotel: false,
  ownerIndex: null,
};

const hevronHiTech = {
  type: "property",
  name: "Hevron Hi Tech",
  colorGroup: "gold",
  price: 180,
  rent: { base: 25, house1: 60, house2: 175, house3: 500, hotel: 600 },
  buildCost: { house: 60, hotel: 100 },
  houses: 0,
  hotel: false,
  ownerIndex: null,
};

// --- Board events map ---
const boardEvents = {
  3: { type: "property", card: schemRoyalEstates },
  1: { type: "property", card: schemYosephGardens },
  4: { type: "property", card: schemDreamResorts },
  7: { type: "property", card: ephraimHilltops },
  11: { type: "property", card: gushKatif },
  12: { type: "property", card: neveDekalim },
  14: { type: "property", card: ganOr },
  29: { type: "property", card: jerusalemHills },
  28: { type: "property", card: jerusalemHillsOrchard },
  35: { type: "property", card: hevronElonMamrei },
  37: { type: "property", card: hevronLuxuryCondos },
  38: { type: "property", card: hevronHiTech },
};

// --- Board positions generator ---
function buildBoardPositions(refSize = 1200, margin = 100, spacesPerSide = 11) {
  const positions = [];
  const step = (refSize - 2 * margin) / (spacesPerSide - 1);

  const topY = margin;
  for (let i = 0; i < spacesPerSide; i++) positions.push({ x: Math.round(margin + i * step), y: topY });
  const rightX = refSize - margin;
  for (let i = 1; i < spacesPerSide; i++) positions.push({ x: rightX, y: Math.round(topY + i * step) });
  const bottomY = refSize - margin;
  for (let i = 1; i < spacesPerSide; i++) positions.push({ x: Math.round(rightX - i * step), y: bottomY });
  const leftX = margin;
  for (let i = 1; i < spacesPerSide - 1; i++) positions.push({ x: leftX, y: Math.round(bottomY - i * step) });

  return positions.slice(0, 44);
}

const referenceSize = 1200;
const defaultBoardPositions = buildBoardPositions(referenceSize, 100, 11);

// --- Modal Component ---
function CardModal({ card, onClose, mode, currentPlayer, updatePlayer, players, updatePlayers }) {
  if (!card) return null;

  const isProperty = mode === "property";

  const owner = card.ownerIndex !== null ? players[card.ownerIndex] : null;
  const isOwnedByAnother = owner && owner.index !== currentPlayer.index;

  const handleBuyProperty = () => {
    if (currentPlayer.money < card.price) {
      alert("Not enough money to buy this property!");
      return;
    }
    const updatedPlayers = [...players];
    updatedPlayers[currentPlayer.index].money -= card.price;
    card.ownerIndex = currentPlayer.index;
    updatePlayers(updatedPlayers);
    alert(`${currentPlayer.name} bought ${card.name} for $${card.price}`);
    onClose();
  };

  const handlePayRent = () => {
    let rentAmount = card.rent.base;
    if (card.hotel) rentAmount = card.rent.hotel;
    else if (card.houses === 3) rentAmount = card.rent.house3;
    else if (card.houses === 2) rentAmount = card.rent.house2;
    else if (card.houses === 1) rentAmount = card.rent.house1;

    if (currentPlayer.money < rentAmount) {
      alert("Not enough money to pay rent!");
      return;
    }

    const updatedPlayers = [...players];
    updatedPlayers[currentPlayer.index].money -= rentAmount;
    updatedPlayers[owner.index].money += rentAmount;
    updatePlayers(updatedPlayers);
    alert(`${currentPlayer.name} paid $${rentAmount} rent to ${owner.name}`);
    onClose();
  };

  return (
    <div style={modalStyles.overlay}>
      <div style={modalStyles.modal}>
        <h2>{card.name}</h2>
        {isProperty && (
          <>
            <div style={{ height: 20, backgroundColor: card.colorGroup, marginBottom: 10, borderRadius: 4 }}></div>
            <p>Price: ${card.price}</p>
            <p>Rent: ${card.rent.base}</p>
            <p>Rent with 1 House: ${card.rent.house1}</p>
            <p>Rent with 2 Houses: ${card.rent.house2}</p>
            <p>Rent with 3 Houses: ${card.rent.house3}</p>
            <p>Rent with Hotel: ${card.rent.hotel}</p>
            <p>House Cost: ${card.buildCost.house}</p>
            <p>Hotel Cost: ${card.buildCost.hotel}</p>
            <p>Owner: {owner ? owner.name : "None"}</p>
            <p>Your Money: ${currentPlayer.money}</p>

            {!isOwnedByAnother && (
              <button style={{ ...modalStyles.button, backgroundColor: "green" }} onClick={handleBuyProperty}>Buy Property</button>
            )}
            {isOwnedByAnother && (
              <button style={{ ...modalStyles.button, backgroundColor: "orange" }} onClick={handlePayRent}>Pay Rent</button>
            )}

            <button style={modalStyles.button} onClick={onClose}>Close</button>
          </>
        )}
      </div>
    </div>
  );
}

// --- Styles ---
const modalStyles = {
  overlay: { position: "fixed", top: 0, left: 0, right: 0, bottom: 0, backgroundColor: "rgba(0,0,0,0.5)", display: "flex", justifyContent: "center", alignItems: "center", zIndex: 1000 },
  modal: { backgroundColor: "#fff", padding: 30, borderRadius: 12, minWidth: 300, maxWidth: "90%", textAlign: "center", boxShadow: "0 5px 15px rgba(0,0,0,0.3)" },
  button: { margin: "8px 5px", padding: "8px 15px", borderRadius: 6, border: "none", backgroundColor: "#007bff", color: "#fff", fontSize: 14, cursor: "pointer" },
};

// --- Main App ---
function App() {
  const [players, setPlayers] = useState([]);
  const [newPlayerName, setNewPlayerName] = useState("");
  const [newPlayerColor, setNewPlayerColor] = useState("");
  const [gameStarted, setGameStarted] = useState(false);
  const [currentPlayerIndex, setCurrentPlayerIndex] = useState(0);
  const [qaMode, setQaMode] = useState(false);
  const [currentCard, setCurrentCard] = useState(null);
  const [boardWidth, setBoardWidth] = useState(Math.min(window.innerWidth * 0.95, referenceSize));
  const [boardPositions, setBoardPositions] = useState(defaultBoardPositions);
  const [diceRolls, setDiceRolls] = useState([]);

  const availableColors = ["black", "purple", "blue", "brown", "orange", "red", "green"];
  const maxPlayers = 7;
  const scale = boardWidth / referenceSize;

  useEffect(() => {
    const handleResize = () => setBoardWidth(Math.min(window.innerWidth * 0.95, referenceSize));
    window.addEventListener("resize", handleResize);
    return () => window.removeEventListener("resize", handleResize);
  }, []);

  const addPlayer = () => {
    if (!newPlayerName || !newPlayerColor) return;
    if (players.some(p => p.color === newPlayerColor)) { alert("Color taken!"); return; }
    setPlayers([...players, { name: newPlayerName, color: newPlayerColor, position: 0, zchutPoints: 1000, money: 2000, missTurn: false, index: players.length }]);
    setNewPlayerName(""); setNewPlayerColor("");
  };

  const startGame = () => {
    if (players.length < 2) { alert("At least 2 players required."); return; }
    setGameStarted(true);
  };

  const updateCurrentPlayer = (updatedPlayer) => {
    const updatedPlayers = [...players];
    updatedPlayers[currentPlayerIndex] = updatedPlayer;
    setPlayers(updatedPlayers);
  };

  const movePlayerBy = (steps) => {
    if (steps <= 0 || players.length === 0) return;
    const speedMs = 220;
    const updatedPlayers = [...players];
    const startIndex = updatedPlayers[currentPlayerIndex].position;
    let stepCount = 0;

    const doStep = () => {
      stepCount++;
      updatedPlayers[currentPlayerIndex].position = (startIndex + stepCount) % boardPositions.length;
      setPlayers([...updatedPlayers]);

      if (stepCount < steps) setTimeout(doStep, speedMs);
      else {
        const landedIndex = updatedPlayers[currentPlayerIndex].position;
        const event = boardEvents[landedIndex];
        if (event?.type === "property") setQaMode("property") || setCurrentCard(event.card);
      }
    };
    doStep();
  };

  const rollDice = (val) => {
    setDiceRolls(prev => {
      const newRolls = [...prev, val];
      if (newRolls.length === 2) {
        movePlayerBy(newRolls[0] + newRolls[1]);
        return [];
      }
      return newRolls;
    });
  };

  const endTurn = () => {
    const updatedPlayers = [...players];
    if (updatedPlayers[currentPlayerIndex].missTurn) {
      updatedPlayers[currentPlayerIndex].missTurn = false;
      alert(`${updatedPlayers[currentPlayerIndex].name} skips this turn!`);
    }
    setPlayers(updatedPlayers);
    setCurrentPlayerIndex(prev => (players.length > 0 ? (prev + 1) % players.length : 0));
  };

  return (
    <div style={styles.container}>
      <h1>TorahPoly Monopoly Game</h1>

      {!gameStarted ? (
        <>
          {players.length < maxPlayers && (
            <div style={styles.inputRow}>
              <input type="text" placeholder="Player Name" value={newPlayerName} onChange={(e) => setNewPlayerName(e.target.value)} style={styles.input} />
              <select value={newPlayerColor} onChange={(e) => setNewPlayerColor(e.target.value)} style={styles.input}>
                <option value="">Choose Color</option>
                {availableColors.filter(c => !players.some(p => p.color === c)).map(c => <option key={c} value={c}>{c}</option>)}
              </select>
              <button onClick={addPlayer} style={styles.button}>Add Player</button>
            </div>
          )}
          <h2>Joined Players ({players.length}/{maxPlayers})</h2>
          <ul>
            {players.map((p, i) => (
              <li key={i} style={{ color: p.color, fontWeight: i === currentPlayerIndex ? "bold" : "normal" }}>{p.name} ({p.color})</li>
            ))}
          </ul>
          <button onClick={startGame} style={{ ...styles.button, marginTop: 20 }}>Start Game</button>
        </>
      ) : (
        <>
          <div style={{ marginBottom: 20 }}>
            <h2>Players</h2>
            <ul>
              {players.map((p, i) => (
                <li key={i} style={{ color: p.color, fontWeight: i === currentPlayerIndex ? "bold" : "normal" }}>
                  {p.name} - Position: {p.position}, Zchut: {p.zchutPoints}, Money: ${p.money} {i === currentPlayerIndex && "(Your Turn)"} {p.missTurn && "(Miss next turn)"}
                </li>
              ))}
            </ul>
          </div>

          {/* Game Board */}
          <div style={{ position: "relative", display: "inline-block", marginBottom: 20 }}>
            <img src={boardImage} alt="Game Board" style={{ width: boardWidth, maxWidth: "95vw", height: "auto", border: "2px solid #333", borderRadius: 12, display: "block" }} />
            {players.map((player, idx) => {
              const pos = boardPositions[player.position % boardPositions.length];
              const left = Math.round(pos.x * scale) - 15;
              const top = Math.round(pos.y * scale) - 15;
              return (
                <div key={idx} style={{ position: "absolute", width: 30, height: 30, borderRadius: "50%", backgroundColor: player.color, left, top, border: "2px solid #fff", display: "flex", justifyContent: "center", alignItems: "center", color: "#fff", fontWeight: "bold" }}>
                  {idx + 1}
                </div>
              );
            })}
          </div>

          <div style={{ marginBottom: 20 }}>
            <Dice onRoll={(val) => rollDice(val)} />
            <button onClick={endTurn} style={{ ...styles.button, marginLeft: 10 }}>End Turn</button>
          </div>
        </>
      )}

      <CardModal
        card={currentCard}
        onClose={() => { setCurrentCard(null); setQaMode(false); }}
        mode={qaMode}
        currentPlayer={players[currentPlayerIndex]}
        updatePlayer={updateCurrentPlayer}
        players={players}
        updatePlayers={setPlayers}
      />
    </div>
  );
}

// --- Styles ---
const styles = {
  container: { textAlign: "center", fontFamily: "Arial, sans-serif", padding: 20 },
  inputRow: { display: "flex", justifyContent: "center", gap: 10, marginBottom: 20 },
  input: { padding: 6, fontSize: 14 },
  button: { padding: "6px 15px", fontSize: 14, cursor: "pointer", borderRadius: 6, backgroundColor: "#007bff", color: "#fff", border: "none" },
};

export default App;
